#!/bin/bash
# Uninstall script for FineTune
# Generated by IntuneBrew

# Exit on error
set -e

echo "Uninstalling FineTune..."

# Check if running as root
if [ "$EUID" -ne 0 ]; then
  echo "Please run as root"
  exit 1
fi

# Kill application process if running
echo "Stopping FineTune if running..."
pkill -f "FineTune" 2>/dev/null || true

# Remove /Applications/FineTune.app
echo "Removing /Applications/FineTune.app..."
if [ -d "/Applications/FineTune.app" ]; then
    rm -rf "/Applications/FineTune.app" 2>/dev/null || true
elif [ -f "/Applications/FineTune.app" ]; then
    rm -f "/Applications/FineTune.app" 2>/dev/null || true
fi

# Remove $HOME/Library/Application Scripts/com.finetuneapp.FineTune
echo "Removing $HOME/Library/Application Scripts/com.finetuneapp.FineTune..."
if [ -d "$HOME/Library/Application Scripts/com.finetuneapp.FineTune" ]; then
    rm -rf "$HOME/Library/Application Scripts/com.finetuneapp.FineTune" 2>/dev/null || true
elif [ -f "$HOME/Library/Application Scripts/com.finetuneapp.FineTune" ]; then
    rm -f "$HOME/Library/Application Scripts/com.finetuneapp.FineTune" 2>/dev/null || true
fi

# Remove $HOME/Library/Containers/com.finetuneapp.FineTune
echo "Removing $HOME/Library/Containers/com.finetuneapp.FineTune..."
if [ -d "$HOME/Library/Containers/com.finetuneapp.FineTune" ]; then
    rm -rf "$HOME/Library/Containers/com.finetuneapp.FineTune" 2>/dev/null || true
elif [ -f "$HOME/Library/Containers/com.finetuneapp.FineTune" ]; then
    rm -f "$HOME/Library/Containers/com.finetuneapp.FineTune" 2>/dev/null || true
fi

echo "Uninstallation complete!"
exit 0
